// ❌ BAD - using typeof to check for arrays returns wrong result
function processOrderItems(items) {
  if (typeof items === 'object') {
    // BUG: null also passes this check
    items.forEach(item => console.log(item));
  }
}

// ✅ GOOD - use Array.isArray for reliable array detection
function processOrderItems(items) {
  if (Array.isArray(items)) {
    items.forEach(item => console.log(item));
  }
}

// ❌ BAD - equality check always fails for NaN, global isNaN coerces
function isValidPrice(price) {
  if (price === NaN) return false;       // never true
  if (isNaN('free shipping')) return false; // coerces string, wrongly true
}

// ✅ GOOD - Number.isNaN checks without coercion
function isValidPrice(price) {
  if (Number.isNaN(price)) return false;
  return price > 0;
}

// ❌ BAD - relying on var hoisting creates confusing undefined bugs
console.log(discount);   // undefined, not an error - confusing
var discount = 0.1;

// ✅ GOOD - let/const make the TDZ explicit and catch bugs early
console.log(discount);   // ReferenceError: Cannot access before init
const discount = 0.1;

// ❌ BAD - var leaks out of the block, causing subtle bugs
for (var i = 0; i < 3; i++) {}
console.log(i); // 3 - leaked out of the for loop

// ✅ GOOD - let is block-scoped, stays inside the loop
for (let i = 0; i < 3; i++) {}
console.log(i); // ReferenceError - correctly not accessible

// ❌ BAD - string concatenation is fragile and hard to read
const orderSummary = 'Order #' + orderId + ' for ' + customerName + '\n' +
  'Total: $' + (price * qty).toFixed(2);

// ✅ GOOD - template literal is readable and multi-line
const orderSummary = `Order #${orderId} for ${customerName}
Total: $${(price * qty).toFixed(2)}`;

// ❌ BAD - using undefined to intentionally clear a value is confusing
function clearUserSession(session) {
  session.currentUser = undefined; // did JS do this, or did we?
}

// ✅ GOOD - null clearly signals intentional 'no value'
function clearUserSession(session) {
  session.currentUser = null; // we explicitly cleared this
}

// ❌ BAD - regular function loses 'this' inside setTimeout callback
class NotificationService {
  constructor() { this.queue = []; }
  startProcessing() {
    setInterval(function() {
      this.queue.shift(); // TypeError: cannot read 'shift' of undefined
    }, 1000);
  }
}

// ✅ GOOD - arrow function captures 'this' from startProcessing
class NotificationService {
  constructor() { this.queue = []; }
  startProcessing() {
    setInterval(() => {
      this.queue.shift(); // 'this' is the NotificationService instance
    }, 1000);
  }
}

// ❌ BAD - imperative loop mixes filtering and transformation logic
const result = [];
for (let i = 0; i < shipments.length; i++) {
  if (shipments[i].status === 'delayed') {
    result.push(shipments[i].trackingId);
  }
}

// ✅ GOOD - higher-order functions compose into a clear pipeline
const delayedIds = shipments
  .filter(s => s.status === 'delayed')
  .map(s => s.trackingId);

// ❌ BAD - loose equality and + with mixed types causes bugs
function applyDiscount(price, discount) {
  return price + discount; // '100' + 10 = '10010' if price is a string
}
if (cartTotal == '') { clearCart(); } // true when total is 0!

// ✅ GOOD - explicit conversion and strict equality
function applyDiscount(price, discount) {
  return Number(price) + Number(discount); // always numeric addition
}
if (cartTotal === 0) { clearCart(); }

// ❌ BAD - sloppy mode silently creates a global variable
function saveUserData(data) {
  userData = data; // no 'var/let/const' - creates global window.userData
}

// ✅ GOOD - strict mode turns this into a ReferenceError
'use strict';
function saveUserData(data) {
  userData = data; // ReferenceError: userData is not defined
}

// ❌ BAD - var in loop, all handlers share one 'i', all log 3
const buttons = document.querySelectorAll('button');
for (var i = 0; i < buttons.length; i++) {
  buttons[i].addEventListener('click', () => console.log(i)); // always 3
}

// ✅ GOOD - closure counter with private state
function makeRequestCounter(endpoint) {
  let count = 0;
  return function track() {
    count++;
    console.log(`${endpoint} called ${count} times`);
  };
}
const trackLogin = makeRequestCounter('/api/login');
trackLogin(); // /api/login called 1 times
trackLogin(); // /api/login called 2 times

// ❌ BAD - spread is shallow, mutating nested breaks the original
const originalOrder = { id: 1, address: { city: 'London' } };
const copiedOrder = { ...originalOrder };
copiedOrder.address.city = 'Paris'; // also changes originalOrder.address.city!

// ✅ GOOD - structuredClone creates a fully independent deep copy
const originalOrder = { id: 1, address: { city: 'London' } };
const copiedOrder = structuredClone(originalOrder);
copiedOrder.address.city = 'Paris'; // originalOrder.address.city is still 'London'

// ❌ BAD - storing object directly becomes '[object Object]'
localStorage.setItem('userPreferences', userPrefs); // stores '[object Object]'

// ✅ GOOD - serialize with JSON.stringify, deserialize with JSON.parse
localStorage.setItem('userPreferences', JSON.stringify(userPrefs));
const prefs = JSON.parse(localStorage.getItem('userPreferences'));

// Tab-specific checkout state - use sessionStorage
