// ❌ BAD - accessing __proto__ directly is deprecated
const product = new Product('Laptop', 999);
const proto = product.__proto__; // deprecated, avoid

// ✅ GOOD - use Object.getPrototypeOf
function Product(name, price) {
  this.name = name;
  this.price = price;
}
Product.prototype.getLabel = function() {
  return `${this.name}: $${this.price}`;
};
const laptop = new Product('Laptop', 999);
Object.getPrototypeOf(laptop) === Product.prototype; // true

// ❌ BAD - repeating object structure with no shared prototype wastes memory
const order1 = { id: 1, status: 'pending', ship() { return 'shipped'; } };
const order2 = { id: 2, status: 'pending', ship() { return 'shipped'; } };

// ✅ GOOD - class shares methods via prototype, one copy in memory
class Order {
  constructor(id) { this.id = id; this.status = 'pending'; }
  ship() { this.status = 'shipped'; return this; }
}
const order1 = new Order(1);
const order2 = new Order(2);

// ❌ BAD - for...in includes inherited prototype properties
const productCounts = { laptops: 5, phones: 12, tablets: 3 };
for (const key in productCounts) {
  console.log(key); // might include inherited enumerable keys from prototype
}

// ✅ GOOD - Object.entries only iterates own enumerable properties
for (const [category, count] of Object.entries(productCounts)) {
  console.log(`${category}: ${count} in stock`);
}

// ❌ BAD - manual extraction is verbose and error-prone
const customerId = customer.id;
const customerName = customer.name;
const updatedCustomer = Object.assign({}, customer, { lastLogin: Date.now() });

// ✅ GOOD - destructuring and spread are clean and expressive
const { id: customerId, name: customerName, ...otherFields } = customer;
const updatedCustomer = { ...customer, lastLogin: Date.now() };

// ❌ BAD - impure: reads external state and mutates the orders array
let totalRevenue = 0;
function addOrder(orders, order) {
  orders.push(order);           // mutates argument
  totalRevenue += order.amount; // mutates external variable
}

// ✅ GOOD - pure: returns new values, touches nothing external
function addOrder(orders, order) {
  return [...orders, order]; // new array, original untouched
}
function calculateRevenue(orders) {
  return orders.reduce((sum, o) => sum + o.amount, 0);
}

// ❌ BAD - interval never cleared, holds closure and keeps component alive
function startDashboardPolling(dashboard) {
  setInterval(() => dashboard.refresh(), 5000); // leaks if dashboard removed
}

// ✅ GOOD - return cleanup function, always call it on teardown
function startDashboardPolling(dashboard) {
  const intervalId = setInterval(() => dashboard.refresh(), 5000);
  return () => clearInterval(intervalId); // caller must invoke this on cleanup
}

// ❌ BAD - this is the confusing pattern to trace
var a = 20;
Abc(); // logs 10, not 20 - surprising if you miss the shadowing
function Abc() {
  var a = 10; // new variable, not the outer a
  console.log(a);
}

// ✅ GOOD - clearer equivalent showing what happens
function processConfig() {
  const timeout = 20; // outer
  applyTimeout();
  function applyTimeout() {
    const timeout = 10; // inner - shadows outer, prints 10
    console.log(timeout);
  }
}

// ❌ BAD - assuming length equals element count
const invoiceIds = [101, 102, 103];
invoiceIds[99] = 999;
console.log(invoiceIds.length); // 100 - not 4!
for (const id of invoiceIds) {
  console.log(id); // logs 101, 102, 103, then 97 undefined holes, then 999
}

// ✅ GOOD - use .filter(Boolean) or explicit checks to handle sparse arrays
const validIds = invoiceIds.filter(id => id !== undefined);
console.log(validIds.length); // 4 - only the actual values
